document.addEventListener('DOMContentLoaded', () => { const themeToggleBtn = document.getElementById('theme-toggle-btn'); const body = document.body; const savedTheme = localStorage.getItem('theme'); if (savedTheme === 'light') { body.classList.add('light-theme'); updateThemeIcon('light'); } else { updateThemeIcon('dark'); } if (themeToggleBtn) { themeToggleBtn.addEventListener('click', () => { body.classList.toggle('light-theme'); const currentTheme = body.classList.contains('light-theme') ? 'light' : 'dark'; localStorage.setItem('theme', currentTheme); updateThemeIcon(currentTheme); }); } function updateThemeIcon(theme) { if (!themeToggleBtn) return; if (theme === 'light') { themeToggleBtn.innerHTML = ` <svg viewBox="0 0 24 24"> <path d="M12 3c-4.97 0-9 4.03-9 9s4.03 9 9 9 9-4.03 9-9c0-.46-.04-.92-.1-1.36-.98 1.37-2.58 2.26-4.4 2.26-2.98 0-5.4-2.42-5.4-5.4 0-1.81.89-3.42 2.26-4.4-.44-.06-.9-.1-1.36-.1z"/> </svg>`; themeToggleBtn.setAttribute('title', 'Switch to Dark Mode'); } else { themeToggleBtn.innerHTML = ` <svg viewBox="0 0 24 24"> <path d="M12 7c-2.76 0-5 2.24-5 5s2.24 5 5 5 5-2.24 5-5-2.24-5-5-5zM2 13h2c.55 0 1-.45 1-1s-.45-1-1-1H2c-.55 0-1 .45-1 1s.45 1 1 1zm18 0h2c.55 0 1-.45 1-1s-.45-1-1-1h-2c-.55 0-1 .45-1 1s.45 1 1 1zM11 2v2c0 .55.45 1 1 1s1-.45 1-1V2c0-.55-.45-1-1-1s-1 .45-1 1zm0 18v2c0 .55.45 1 1 1s1-.45 1-1v-2c0-.55-.45-1-1-1s-1 .45-1 1zM5.99 4.58c-.39-.39-1.03-.39-1.41 0s-.39 1.03 0 1.41l1.06 1.06c.39.39 1.03.39 1.41 0s.39-1.03 0-1.41L5.99 4.58zm12.37 12.37c-.39-.39-1.03-.39-1.41 0s-.39 1.03 0 1.41l1.06 1.06c.39.39 1.03.39 1.41 0s.39-1.03 0-1.41l-1.06-1.06zm1.06-10.96c.39-.39.39-1.03 0-1.41s-1.03-.39-1.41 0l-1.06 1.06c-.39.39-.39 1.03 0 1.41s1.03.39 1.41 0l1.06-1.06zM7.05 18.01c.39-.39.39-1.03 0-1.41s-1.03-.39-1.41 0l-1.06 1.06c-.39.39-.39 1.03 0 1.41s1.03.39 1.41 0l1.06-1.06z"/> </svg>`; themeToggleBtn.setAttribute('title', 'Switch to Light Mode'); } } const mobileMenuBtn = document.getElementById('mobile-menu-btn'); const navLinks = document.querySelector('.nav-links'); if (mobileMenuBtn && navLinks) { mobileMenuBtn.addEventListener('click', (e) => { e.stopPropagation(); navLinks.classList.toggle('active'); }); document.addEventListener('click', (e) => { if (navLinks.classList.contains('active') && !navLinks.contains(e.target) && e.target !== mobileMenuBtn) { navLinks.classList.remove('active'); } }); navLinks.querySelectorAll('a').forEach(link => { link.addEventListener('click', () => { navLinks.classList.remove('active'); }); }); } const faqItems = document.querySelectorAll('.faq-item'); faqItems.forEach(item => { const question = item.querySelector('.faq-question'); if (question) { question.addEventListener('click', () => { faqItems.forEach(otherItem => { if (otherItem !== item && otherItem.classList.contains('active')) { otherItem.classList.remove('active'); } }); item.classList.toggle('active'); }); } }); const marketSearchInput = document.getElementById('market-search'); if (marketSearchInput) { marketSearchInput.addEventListener('input', (e) => { const query = e.target.value.toLowerCase().trim(); const cards = document.querySelectorAll('.market-link-card'); cards.forEach(card => { const name = card.querySelector('span').textContent.toLowerCase(); if (name.includes(query)) { card.style.display = 'flex'; } else { card.style.display = 'none'; } }); }); } const chartYearFilter = document.getElementById('filter-year'); const chartTextFilter = document.getElementById('search-chart-data'); const tableRows = document.querySelectorAll('.chart-table tbody tr'); function filterChartTable() { if (!tableRows.length) return; const yearVal = chartYearFilter ? chartYearFilter.value : 'all'; const textVal = chartTextFilter ? chartTextFilter.value.toLowerCase().trim() : ''; tableRows.forEach(row => { const dateText = row.getAttribute('data-week'); const year = row.getAttribute('data-year'); if (!dateText) return; let yearMatch = (yearVal === 'all' || year === yearVal); let textMatch = false; if (textVal === '') { textMatch = true; } else { if (dateText.toLowerCase().includes(textVal)) { textMatch = true; } else { const cells = row.querySelectorAll('td'); for (let cell of cells) { if (cell.textContent.toLowerCase().includes(textVal)) { textMatch = true; break; } } } } if (yearMatch && textMatch) { row.classList.remove('filtered-out'); } else { row.classList.add('filtered-out'); } }); } if (chartYearFilter) { chartYearFilter.addEventListener('change', filterChartTable); } if (chartTextFilter) { chartTextFilter.addEventListener('input', filterChartTable); } const btnCopy = document.getElementById('btn-copy'); const btnPrint = document.getElementById('btn-print'); const btnPdf = document.getElementById('btn-pdf'); const btnExcel = document.getElementById('btn-excel'); function getVisibleTableRows() { const table = document.querySelector('.chart-table'); if (!table) return null; const headers = Array.from(table.querySelectorAll('thead th')).map(th => th.textContent.trim()); const rows = Array.from(table.querySelectorAll('tbody tr')).filter(tr => !tr.classList.contains('filtered-out')); return { headers, rows }; } if (btnCopy) { btnCopy.addEventListener('click', () => { const data = getVisibleTableRows(); if (!data || data.rows.length === 0) return; let textContent = data.headers.join('\t') + '\n'; data.rows.forEach(tr => { const cells = Array.from(tr.querySelectorAll('td')).map(td => td.textContent.trim()); textContent += cells.join('\t') + '\n'; }); navigator.clipboard.writeText(textContent).then(() => { const originalText = btnCopy.innerHTML; btnCopy.innerHTML = ` <svg viewBox="0 0 24 24"><path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z"/></svg> Copied! `; btnCopy.style.backgroundColor = 'var(--accent-color)'; btnCopy.style.borderColor = 'var(--accent-color)'; btnCopy.style.color = 'white'; setTimeout(() => { btnCopy.innerHTML = originalText; btnCopy.style.backgroundColor = ''; btnCopy.style.borderColor = ''; btnCopy.style.color = ''; }, 2000); }).catch(err => { console.error('Failed to copy text: ', err); }); }); } if (btnPrint) { btnPrint.addEventListener('click', () => { window.print(); }); } if (btnPdf) { btnPdf.addEventListener('click', () => { window.print(); }); } if (btnExcel) { btnExcel.addEventListener('click', () => { const data = getVisibleTableRows(); if (!data || data.rows.length === 0) return; let tableHtml = '<table><thead><tr>'; data.headers.forEach(h => { tableHtml += `<th style="background-color: #4F46E5; color: #ffffff; font-weight: bold; border: 1px solid #dddddd; padding: 8px;">${h}</th>`; }); tableHtml += '</tr></thead><tbody>'; data.rows.forEach(tr => { tableHtml += '<tr>'; const cells = Array.from(tr.querySelectorAll('td')); cells.forEach((td, idx) => { const val = td.textContent.trim(); let style = 'border: 1px solid #dddddd; padding: 8px; text-align: center;'; if (td.classList.contains('red-jodi')) { style += ' color: #e11d48; font-weight: bold; background-color: #ffe4e6;'; } tableHtml += `<td style="${style}">${val}</td>`; }); tableHtml += '</tr>'; }); tableHtml += '</tbody></table>'; const fileTemplate = ` <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40"> <head> <!--[if gte mso 9]> <xml> <x:ExcelWorkbook> <x:ExcelWorksheets> <x:ExcelWorksheet> <x:Name>Jodi Chart Records</x:Name> <x:WorksheetOptions> <x:DisplayGridlines/> </x:WorksheetOptions> </x:ExcelWorksheet> </x:ExcelWorksheets> </x:ExcelWorkbook> </xml> <![endif]--> <meta http-equiv="content-type" content="text/html; charset=UTF-8"> </head> <body> ${tableHtml} </body> </html> `; const blob = new Blob([fileTemplate], { type: 'application/vnd.ms-excel' }); const url = URL.createObjectURL(blob); const a = document.createElement('a'); const marketName = document.querySelector('h1').textContent.split('Jodi')[0].trim().replace(/\s+/g, '-').toLowerCase(); a.href = url; a.download = `${marketName}-jodi-chart.xls`; document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url); }); } });
